+fn parse_graphml_directed_value(value: &[u8]) -> Option<bool> {
+    let text = std::str::from_utf8(value).ok()?;
+    match text.trim().to_ascii_lowercase().as_str() {
+        "true" | "1" => Some(true),
+        "false" | "0" => Some(false),
+        _ => None,
+    }
+}
